mapper.select:
SELECT 'joined' AS source_type, gw.id AS group_work_id, ga.id AS activity_id, ga.title, ga.cpu, ga.memory, ga.storage, ga.base_price, gw.actual_price, ga.total_duration, ga.start_time, gw.server_start_time, gw.server_expire_time, gw.group_status, CASE gw.group_status WHEN 0 THEN '进行中' WHEN 1 THEN '已成团' WHEN 2 THEN '已取消/过期' ELSE '未知' END AS group_status_text, go.order_no, go.status AS order_status, gw.join_time, NULL AS admin_contact FROM osh_group_activity ga LEFT JOIN osh_group_work gw ON ga.id = gw.group_activity_id LEFT JOIN osh_group_order go ON gw.order_id = go.id WHERE gw.user_id = #{userId}
AND gw.group_status = #{groupStatus}
UNION ALL
SELECT 'initiated' AS source_type, gui.id AS group_work_id, gui.activity_id AS activity_id, COALESCE(ga.title, '未知活动') AS title, COALESCE(ga.cpu, '待定') AS cpu, COALESCE(ga.memory, '待定') AS memory, COALESCE(ga.storage, '待定') AS storage, ga.base_price, gui.custom_price AS actual_price, gui.duration AS total_duration, gui.initiate_time AS start_time, gui.server_start_time, gui.server_expire_time, gui.group_status, CASE gui.group_status WHEN 0 THEN '招募中' WHEN 1 THEN '已成团' WHEN 2 THEN '已取消/过期' ELSE '未知' END AS group_status_text, go.order_no, go.status AS order_status, gui.initiate_time AS join_time, ga.admin_contact FROM osh_group_user_initiated gui LEFT JOIN osh_group_activity ga ON gui.activity_id = ga.id LEFT JOIN osh_group_order go ON gui.order_id = go.id WHERE gui.user_id = #{userId} AND gui.delete_flag = 0
AND gui.group_status = #{groupStatus}
ORDER BY join_time DESC

SELECT COUNT(*)
FROM osh_group_work
WHERE group_activity_id = #{groupActivityId}
  AND user_id = #{userId}

mapper.update:
UPDATE osh_group_activity
SET current_num = #{currentNum},
    status = #{status},
    update_time = #{updateTime}
WHERE id = #{id}

UPDATE osh_group_activity
SET status = 3,
    update_time = #{updateTime}
WHERE id = #{id}
